import { useState } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import Skills from './components/Skills';
import Projects from './components/Projects';
import Experience from './components/Experience';
import Contact from './components/Contact';
import ResumeView from './components/ResumeView';
import Footer from './components/Footer';

export default function App() {
  const [activeSection, setActiveSection] = useState('about');

  const renderSection = () => {
    // Map section IDs to components
    switch (activeSection.toLowerCase()) {
      case 'about': return <Hero setActiveSection={setActiveSection} />;
      case 'skills': return <Skills />;
      case 'projects': return <Projects />;
      case 'experience': return <Experience />;
      case 'contact': return <Contact />;
      case 'resume': return <ResumeView />;
      default: return <Hero />;
    }
  };

  return (
    <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--bg)' }}>
      <Navbar activeSection={activeSection} setActiveSection={setActiveSection} />

      <main style={{ flex: 1, position: 'relative', overflowY: 'auto', paddingBottom: '2rem' }}>
        <div
          key={activeSection}
          style={{
            height: '100%',
            animation: 'fadeIn 0.5s ease-out forwards'
          }}
        >
          {renderSection()}
        </div>
      </main>

      <Footer />

      {/* Inline styles for section transitions */}
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  );
}
